#include <stdio.h>
#include <string.h>

int maxConsecutive(char *s, int n) {
    int max = 0;
    for (int i = 0; i < n; i++) {
        int count = 0;
        char c = s[i];
        for (int j = i; j < n; j++) {
            if (s[j] == c) {
                count++;
            } else {
                break;
            }
        }
        max = (max > count) ? max : count;
    }
    return max;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        char s[105];
        scanf("%s", s);
        int n = strlen(s);
        int minB = n;
        for (int i = 0; i < n; i++) {
            char temp = s[i];
            if (s[i] == 'R') {
                s[i] = 'A';
            } else {
                s[i] = 'R';
            }
            int b = maxConsecutive(s, n);
            minB = (minB < b) ? minB : b;
            s[i] = temp;
        }
        printf("Case %d: %d\n", t + 1, minB);
    }
    return 0;
}

