import java.util.Scanner;
public class Main {
    public static int maxConsecutive(String s) {
        int max = 0;
        for (int i = 0; i < s.length(); i++) {
            int count = 0;
            char c = s.charAt(i);
            for (int j = i; j < s.length(); j++) {
                if (s.charAt(j) == c) {
                    count++;
                } else {
                    break;
                }
            }
            max = (max > count) ? max : count;
        }
        return max;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        for (int t = 0; t < T; t++) {
            String s = sc.next();
            int minB = s.length();
            for (int i = 0; i < s.length(); i++) {
                char[] arr = s.toCharArray();
                if (arr[i] == 'R') {
                    arr[i] = 'A';
                } else {
                    arr[i] = 'R';
                }
                String temp = new String(arr);
                int b = maxConsecutive(temp);
                minB = (minB < b) ? minB : b;
            }
            System.out.println("Case " + (t + 1) + ": " + minB);
        }
    }
}

